        Self.togglePlayerSizeHD = function() {
            var isChrome69 = /chrome\/([6][9])\./.test(navigator.userAgent.toLowerCase());
            if(isChrome69) {
                setTimeout(function(){
                    page_params.chrome_69_bandaid = {
